import { Trip, Truck, Employee, Customer, Location, TripFuel, SystemUser } from '../types';

const BASE_URL = '/api'; // Standard Django API prefix

// Helper for Django CSRF if needed (standard for sessions)
const getHeaders = () => ({
  'Content-Type': 'application/json',
  'Accept': 'application/json',
});

export const api = {
  // Trips
  getTrips: async (): Promise<Trip[]> => {
    const res = await fetch(`${BASE_URL}/trips/`);
    return res.json();
  },
  createTrip: async (trip: Omit<Trip, 'trip_id'>): Promise<Trip> => {
    const res = await fetch(`${BASE_URL}/trips/`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(trip),
    });
    return res.json();
  },
  updateTrip: async (id: number, trip: Partial<Trip>): Promise<Trip> => {
    const res = await fetch(`${BASE_URL}/trips/${id}/`, {
      method: 'PATCH',
      headers: getHeaders(),
      body: JSON.stringify(trip),
    });
    return res.json();
  },

  // Trucks
  getTrucks: async (): Promise<Truck[]> => {
    const res = await fetch(`${BASE_URL}/trucks/`);
    return res.json();
  },
  createTruck: async (truck: Omit<Truck, 'truck_id'>): Promise<Truck> => {
    const res = await fetch(`${BASE_URL}/trucks/`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(truck),
    });
    return res.json();
  },
  deleteTruck: async (id: number): Promise<void> => {
    await fetch(`${BASE_URL}/trucks/${id}/`, { method: 'DELETE' });
  },

  // Employees
  getEmployees: async (): Promise<Employee[]> => {
    const res = await fetch(`${BASE_URL}/employees/`);
    return res.json();
  },

  // Locations & Customers (Reference Data)
  getLocations: async (): Promise<Location[]> => {
    const res = await fetch(`${BASE_URL}/locations/`);
    return res.json();
  },
  getCustomers: async (): Promise<Customer[]> => {
    const res = await fetch(`${BASE_URL}/customers/`);
    return res.json();
  },

  // Auth simulation for Django
  login: async (username: string, password: string): Promise<SystemUser> => {
    const res = await fetch(`${BASE_URL}/auth/login/`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify({ username, password }),
    });
    if (!res.ok) throw new Error('Invalid Credentials');
    return res.json();
  }
};

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import TripList from './components/TripList';
import Login from './components/Login';
import TruckList from './components/TruckList';
import EmployeeList from './components/EmployeeList';
import Hub from './components/Hub';
import UserManagement from './components/UserManagement';
import AppNavbar from './components/AppNavbar';
import { ClipboardList, Package, DollarSign, Loader2 } from 'lucide-react';
import { api } from './services/apiService';
import { 
  Trip, Employee, Customer, Location, Truck, TripFuel, 
  SystemUser, AppModule, Theme 
} from './types';

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<SystemUser | null>(null);
  const [loginError, setLoginError] = useState<string | null>(null);

  // Navigation State
  const [activeModule, setActiveModule] = useState<AppModule | 'hub' | null>(null);
  const [currentView, setCurrentView] = useState('dashboard');

  // Theme State
  const [theme, setTheme] = useState<Theme>('dark');

  // Database State
  const [isLoading, setIsLoading] = useState(false);
  const [systemUsers, setSystemUsers] = useState<SystemUser[]>([]);
  const [trips, setTrips] = useState<Trip[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [locations, setLocations] = useState<Location[]>([]);
  const [trucks, setTrucks] = useState<Truck[]>([]);
  const [fuels, setFuels] = useState<TripFuel[]>([]);

  // Theme Effect
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  // Data Hydration Effect
  useEffect(() => {
    if (currentUser) {
      loadInitialData();
    }
  }, [currentUser]);

  const loadInitialData = async () => {
    setIsLoading(true);
    try {
      const [t, e, c, l, v] = await Promise.all([
        api.getTrips(),
        api.getEmployees(),
        api.getCustomers(),
        api.getLocations(),
        api.getTrucks()
      ]);
      setTrips(t);
      setEmployees(e);
      setCustomers(c);
      setLocations(l);
      setTrucks(v);
    } catch (error) {
      console.error("Failed to load data from Django backend", error);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  // --- AUTH HANDLERS ---
  const handleLogin = async (username: string, password: string) => {
    try {
      // In a real Django setup, we'd call api.login
      // For this demo environment, we maintain the mock logic but prepared for async
      if (username === 'SuperAdmin' && password === 'admin123') {
        setCurrentUser({ 
          id: 1, 
          username: 'SuperAdmin', 
          role: 'SuperAdmin', 
          permissions: ['inventory', 'trip_scheduling', 'billing'] 
        });
        setActiveModule('hub');
        setLoginError(null);
      } else {
        setLoginError("Invalid credentials. Try 'SuperAdmin' / 'admin123'");
      }
    } catch (err) {
      setLoginError("Backend connection failed.");
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveModule(null);
    setCurrentView('dashboard');
  };

  const handleModuleSelect = (module: AppModule | 'hub') => {
    setActiveModule(module);
    if (module !== 'hub') {
      setCurrentView('dashboard');
    }
  };

  // --- ASSET CRUD HANDLERS (Now Async Ready) ---
  const handleAddTruck = async (newTruck: Omit<Truck, 'truck_id'>) => {
    const created = await api.createTruck(newTruck);
    setTrucks([...trucks, created]);
  };

  const handleDeleteTruck = async (id: number) => {
    await api.deleteTruck(id);
    setTrucks(trucks.filter(t => t.truck_id !== id));
  };

  // --- RENDER LOGIC ---

  if (!currentUser) {
    return (
      <Login 
        onLogin={handleLogin} 
        error={loginError} 
        theme={theme}
        onToggleTheme={toggleTheme}
      />
    );
  }

  if (activeModule === 'hub') {
    return (
      <Hub 
        user={currentUser} 
        onSelectModule={handleModuleSelect} 
        onLogout={handleLogout} 
        theme={theme}
        onToggleTheme={toggleTheme}
      />
    );
  }

  return (
    <div className="flex h-screen bg-navy-50 dark:bg-carbon-950 transition-colors duration-300">
      <Sidebar 
        currentView={currentView} 
        setCurrentView={setCurrentView} 
        onLogout={handleLogout}
        username={currentUser.username}
        userRole={currentUser.role}
        theme={theme}
      />
      <main className="flex-1 flex flex-col h-screen overflow-hidden relative">
        <AppNavbar activeModule="trip_scheduling" onSelectModule={handleModuleSelect} />

        {isLoading && (
          <div className="absolute inset-0 bg-white/50 dark:bg-carbon-950/50 backdrop-blur-[1px] z-[60] flex items-center justify-center">
             <div className="flex flex-col items-center gap-3">
               <Loader2 className="w-8 h-8 text-navy-900 dark:text-white animate-spin" />
               <p className="text-sm font-medium text-navy-600 dark:text-carbon-400">Syncing with Django...</p>
             </div>
          </div>
        )}

        <div className="flex-1 overflow-hidden relative">
          {(() => {
            switch (currentView) {
              case 'dashboard':
                return <Dashboard trips={trips} trucks={trucks} fuels={fuels} theme={theme} />;
              case 'trips':
                return (
                  <TripList 
                    trips={trips} 
                    setTrips={setTrips} 
                    employees={employees}
                    customers={customers}
                    locations={locations}
                    trucks={trucks}
                    theme={theme}
                  />
                );
              case 'trucks':
                return (
                  <TruckList 
                    trucks={trucks}
                    onAdd={handleAddTruck}
                    onUpdate={() => {}} // Implementation placeholder
                    onDelete={handleDeleteTruck}
                  />
                );
              default:
                return <Dashboard trips={trips} trucks={trucks} fuels={fuels} theme={theme} />;
            }
          })()}
        </div>
      </main>
    </div>
  );
};

export default App;
